class Translator:
    def __init__(self, lang="EN"):
        self.lang = lang

    def __call__(self, english_text, **kwargs):
        entry = _TR.get(english_text)
        if entry:
            text = entry.get(self.lang) or english_text
        else:
            text = english_text
        if kwargs:
            text = text.format(**kwargs)
        return text

    def set_language(self, lang):
        if lang in LANGUAGE_NAMES:
            self.lang = lang


_tr = Translator()
